ValidationRule.errorConditionFormula:
OR(
    AND(
        OR(
            ISPICKVAL(program_name__c , "CPA"),
            ISPICKVAL(program_name__c , "CMA")
        ),
        Amount_requested__c > 79000
    ),
    AND(
        ISPICKVAL(program_name__c , "CAIRA"),
        Amount_requested__c > 40000
    )
)
